/*
 * RAID Level Simulation in C
 * Demonstrates RAID 0 (Striping), RAID 1 (Mirroring), RAID 5 (Distributed Parity)
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define BLOCK_SIZE 512
#define NUM_DISKS 4
#define DATA_DISKS 3 // For RAID 5

/* Data block structure */
typedef struct {
 int block_number;
 char data[BLOCK_SIZE];
 int is_parity; // 1 if this is a parity block
} DiskBlock;

/* RAID 0: Striping - Data split across disks without redundancy */
void raid0_write(DiskBlock disks[], int block_num, char *data) {
 int disk_index = block_num % NUM_DISKS; // Round-robin striping
 int offset = block_num / NUM_DISKS;

 DiskBlock *block = &disks[disk_index * 100 + offset]; // Simple mapping
 block->block_number = block_num;
 memcpy(block->data, data, BLOCK_SIZE);
 block->is_parity = 0;

 printf("RAID 0: Wrote block %d to disk %d (stripe %d)\n", 
 block_num, disk_index, offset);
}

char* raid0_read(DiskBlock disks[], int block_num) {
 int disk_index = block_num % NUM_DISKS;
 int offset = block_num / NUM_DISKS;

 return disks[disk_index * 100 + offset].data;
}

/* RAID 1: Mirroring - Data duplicated on all disks */
void raid1_write(DiskBlock disks[], int block_num, char *data) {
 for (int i = 0; i < NUM_DISKS; i++) {
 DiskBlock *block = &disks[i * 100];
 block->block_number = block_num;
 memcpy(block->data, data, BLOCK_SIZE);
 block->is_parity = 0;

 printf("RAID 1: Wrote block %d to disk %d (mirror)\n", block_num, i);
 }
}

char* raid1_read(DiskBlock disks[], int block_num) {
 // Read from first available disk (could add error checking)
 return disks[0].data;
}

/* XOR Parity Calculation */
void calculate_parity(char *data[], char *parity) {
 memset(parity, 0, BLOCK_SIZE);
 for (int i = 0; i < DATA_DISKS; i++) {
 for (int j = 0; j < BLOCK_SIZE; j++) {
 parity[j] ^= data[i][j]; // XOR all data blocks
 }
 }
}

/* RAID 5: Distributed Parity - Data + parity distributed across disks */
void raid5_write(DiskBlock disks[], int block_num, char *data) {
 int stripe = block_num / DATA_DISKS;
 int parity_disk = stripe % (DATA_DISKS + 1);

 // Write data blocks
 for (int i = 0; i < DATA_DISKS; i++) {
 if (i == parity_disk) continue; // Skip parity disk for data

 int disk_idx = (i + stripe) % (DATA_DISKS + 1);
 int disk_num = disk_idx < parity_disk ? disk_idx : disk_idx + 1;

 DiskBlock *block = &disks[disk_num * 100 + stripe];
 block->block_number = block_num;
 memcpy(block->data, data + (i * BLOCK_SIZE), BLOCK_SIZE);

 printf("RAID 5: Wrote data block %d (stripe %d) to disk %d\n",
 block_num, stripe, disk_num);
 }

 // Calculate and write parity
 char *data_blocks[DATA_DISKS];
 char parity[BLOCK_SIZE];

 // For simplicity, assume we're writing same data as parity
 calculate_parity(data_blocks, parity);

 DiskBlock *parity_block = &disks[parity_disk * 100 + stripe];
 parity_block->block_number = block_num;
 memcpy(parity_block->data, parity, BLOCK_SIZE);
 parity_block->is_parity = 1;

 printf("RAID 5: Wrote parity for stripe %d to disk %d\n", stripe, parity_disk);
}

/* Simulate disk failure and recovery for RAID 5 */
void raid5_recover(DiskBlock disks[], int failed_disk, int stripe) {
 char recovered_data[BLOCK_SIZE];
 memset(recovered_data, 0, BLOCK_SIZE);

 printf("RAID 5: Recovering data from failed disk %d, stripe %d\n", 
 failed_disk, stripe);

 // XOR all remaining data and parity to reconstruct
 for (int i = 0; i < NUM_DISKS; i++) {
 if (i == failed_disk) continue;

 DiskBlock *block = &disks[i * 100 + stripe];
 for (int j = 0; j < BLOCK_SIZE; j++) {
 recovered_data[j] ^= block->data[j];
 }
 }

 printf("RAID 5: Recovered data from stripe %d\n", stripe);
}

/* Print RAID configuration summary */
void print_raid_summary(int raid_level) {
 printf("\n========================================\n");
 printf("RAID Level: %d\n", raid_level);
 printf("========================================\n");

 switch(raid_level) {
 case 0:
 printf("Type: Striping (No Redundancy)\n");
 printf("Disks: %d\n", NUM_DISKS);
 printf("Capacity: %d blocks\n", NUM_DISKS * 10);
 printf("Fault Tolerance: None\n");
 printf("Read Performance: Excellent (parallel)\n");
 printf("Write Performance: Excellent (parallel)\n");
 break;
 case 1:
 printf("Type: Mirroring\n");
 printf("Disks: %d\n", NUM_DISKS);
 printf("Capacity: 1 block (effective)\n");
 printf("Fault Tolerance: N-1 disks\n");
 printf("Read Performance: Excellent (any disk)\n");
 printf("Write Performance: Good (write to all)\n");
 break;
 case 5:
 printf("Type: Block-Level Striping with Distributed Parity\n");
 printf("Disks: %d\n", NUM_DISKS);
 printf("Capacity: %d blocks\n", DATA_DISKS * 10);
 printf("Fault Tolerance: 1 disk\n");
 printf("Read Performance: Good (parallel)\n");
 printf("Write Performance: Good (parity overhead)\n");
 break;
 }
 printf("========================================\n\n");
}

int main() {
 printf("RAID SIMULATION DEMONSTRATION\n");
 printf("=============================\n\n");

 // Demonstrate each RAID level
 print_raid_summary(0);

 DiskBlock raid0_disks[NUM_DISKS * 100];
 char test_data[BLOCK_SIZE] = "Hello, RAID World!";
 raid0_write(raid0_disks, 0, test_data);
 raid0_write(raid0_disks, 1, test_data);
 raid0_write(raid0_disks, 2, test_data);

 print_raid_summary(1);

 DiskBlock raid1_disks[NUM_DISKS * 100];
 raid1_write(raid1_disks, 0, test_data);

 print_raid_summary(5);

 DiskBlock raid5_disks[NUM_DISKS * 100];
 raid5_write(raid5_disks, 0, test_data);

 // Demonstrate recovery
 printf("\n--- Simulating Disk Failure ---\n");
 raid5_recover(raid5_disks, 1, 0);

 return 0;
}
